  // equivalent. Normalize both so that the add result is on the LHS, then
  // check if the predicates match and the RHS operands are the two add
  // operands (in either order).
  // icmp ult (add X, Y), X  ⟺  icmp ult (add X, Y), Y
  // icmp ugt X, (add X, Y)  ⟺  icmp ugt Y, (add X, Y)
  {
    CmpInst::Predicate OrigLPred = LHS->getPredicate();
    // Normalize: put add on LHS for both.
    CmpInst::Predicate LCanonPred = OrigLPred;
    Value *LAdd = L0, *LOp = L1;
    if (match(L1, m_Add(m_Value(), m_Value()))) {
      LAdd = L1;
      LOp = L0;
      LCanonPred = CmpInst::getSwappedPredicate(OrigLPred);
    }
    CmpInst::Predicate RCanonPred = RPred;
    const Value *RAdd = R0, *ROp = R1;
    if (match(R1, m_Add(m_Value(), m_Value()))) {
      RAdd = R1;
      ROp = R0;
      RCanonPred = CmpInst::getSwappedPredicate(RPred);
    }
    // Same canonical predicate and same add result?
    if (LAdd == RAdd && LCanonPred == RCanonPred &&
        (LCanonPred == CmpInst::ICMP_ULT || LCanonPred == CmpInst::ICMP_UGE)) {
      const auto *BO = cast<BinaryOperator>(LAdd);
      Value *AddOp0 = BO->getOperand(0);
      Value *AddOp1 = BO->getOperand(1);
      if ((LOp == AddOp0 && ROp == AddOp1) || (LOp == AddOp1 && ROp == AddOp0))
        return LHSIsTrue;
    }
  }'"}

